// friday13.cs — Find earliest Friday the 13th and count them in a 400-year cycle

// Earliest Friday the 13th starting from 0001-01-01 (proleptic Gregorian)
var date = new DateOnly(1, 1, 13);
while (date.DayOfWeek != DayOfWeek.Friday)
{
    date = date.AddMonths(1);
}
Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd}");

// Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
var start = new DateOnly(1, 1, 13);
var end = new DateOnly(401, 1, 1);

var current = start;
while (current < end)
{
    if (current.DayOfWeek == DayOfWeek.Friday)
        count++;
    current = current.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

